+  const errors: ValidationError[] = [];
+
+  // Type validation
+  if (schema.type) {
+    const typeValid = validateType(data, schema.type);
+    if (!typeValid) {
+      errors.push({
+        path: path || 'root',
+        message: `Expected type "${schema.type}", got "${typeof data}"`,
